public String createBatchMigrationTask(List<BatchMigrationItem> items,
                                       String targetSpaceId, Long userId, Boolean isRemained) {
    String batchId = "batch-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 6);

    for (BatchMigrationItem item : items) {
        String sourceSpaceId = item.getSourceSpaceId();
        List<Long> spaceNodeIds = item.getSpaceNodeIds();

        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        String email = user.getEmail();
        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);

        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
        List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream()
                .map(SpaceAppRelVo::new).toList();

        if (isRemained == null) {
            isRemained = true;
        }

        String taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
                MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained);

        // 更新子任务的 batchId
        SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
        task.setBatchId(batchId);
        spaceNodeMigrationTaskService.updateById(task);

        log.info("createBatchMigrationTask: batchId={}, taskId={}, sourceSpaceId={}, nodeCount={}",
                batchId, taskId, sourceSpaceId, spaceNodeIds.size());
    }

